&lt;tr&gt;&lt;td style=&quot;padding:2px 6px;&quot;&gt;What crosses?&lt;/td&gt;&lt;td style=&quot;padding:2px 6px;&quot;&gt;Information only&lt;/td&gt;&lt;td style=&quot;padding:2px 6px;&quot;&gt;Mass, objects (theoretically)&lt;/td&gt;&lt;/tr&gt;
